function hashText(text: string) {
  let h = 0;
  for (let i = 0; i < text.length; i++) h = Math.imul(31, h) + text.charCodeAt(i) | 0;
  return Math.abs(h);
}

function pick<T>(items: T[], seed: number): T {
  return items[Math.abs(seed) % items.length];
}

function joinSentences(parts: string[]) {
  return parts
    .map(p => p.trim())
    .filter(Boolean)
    .map(p => /[.!?。]$/.test(p) ? p : `${p}.`)
    .join(" ")
    .replace(/\s+/g, " ")
    .replace(/서울디아치과 서울디아치과/g, "서울디아치과")
    .trim();
}

function trimByStyle(text: string, style: string) {
  const max = style === "짧게" ? 130 : style === "자세하게" ? 260 : 195;
  if (text.length <= max) return text;
  const sentences = text.match(/[^.!?。]+[.!?。]/g);
  if (!sentences) return text.slice(0, max).trim();
  let out = "";
  for (const sentence of sentences) {
    const next = `${out} ${sentence}`.trim();
    if (next.length <= max) out = next;
  }
  return out || text.slice(0, max).trim();
}

function findById<T extends { id: string }>(items: T[], ids: string[]) {
  return ids.map(id => items.find(item => item.id === id)).filter(Boolean) as T[];
}

function createKeywordReview({ treats, sats, conveniences, emotions, visit, style, tone }: {
  treats: string[];
  sats: string[];
  conveniences: string[];
  emotions: string[];
  visit: string;
  style: string;
  tone: string;
}) {
  const seed = hashText(`${treats.join(",")}-${sats.join(",")}-${conveniences.join(",")}-${emotions.join(",")}-${visit}-${style}-${tone}-${Date.now()}`);
  const selectedTreatments = findById(TREATMENTS, treats);
  const selectedSats = findById(SATISFACTIONS, sats);
  const selectedConvs = findById(CONVENIENCES, conveniences);
  const selectedEmos = findById(EMOTIONS, emotions);
  const main = selectedTreatments[0] || TREATMENTS[TREATMENTS.length - 1];
  const second = selectedTreatments[1];

  const openers = [
    `마곡역 근처 서울디아치과에서 ${main.id} 진료를 받고 왔습니다`,
    `${main.keyword || "마곡 치과"}를 알아보다가 서울디아치과에 방문했습니다`,
    `마곡 치과를 찾다가 서울디아치과에서 ${main.id} 상담과 진료를 받았습니다`,
    `서울디아치과에서 ${main.id} 관련 진료를 받았는데 전반적으로 편안했습니다`,
    `마곡역 치과를 알아보다 서울디아치과에서 ${main.id} 상담을 받았습니다`,
    `마곡에서 치과를 찾던 중 서울디아치과의 ${main.id} 진료를 경험했습니다`,
  ];

  const visitPhrases: Record<string, string[]> = {
    "처음 방문": [
      "처음 방문이라 긴장했지만 안내가 차분해서 부담이 줄었습니다",
      "첫 방문이었는데 접수부터 상담까지 흐름이 깔끔했습니다",
      "처음 가본 치과였지만 설명을 잘해주셔서 편하게 느껴졌습니다",
      "첫 상담부터 분위기가 차분해서 궁금한 점을 묻기 좋았습니다",
      "처음 방문했는데도 안내가 정돈되어 있어 편안했습니다",
    ],
    "재방문": [
      "재방문했는데 이번에도 안내와 진료 과정이 안정적으로 느껴졌습니다",
      "이전 방문 때의 좋은 기억이 있어 다시 찾았고 이번에도 만족스러웠습니다",
      "재방문이라 더 편하게 진료받을 수 있었고 설명도 꼼꼼했습니다",
      "다시 방문해도 상담과 진료 흐름이 일관되어 신뢰가 갔습니다",
      "재방문하면서도 필요한 부분을 다시 확인해주셔서 좋았습니다",
    ],
  };

  const closings = [
    "마곡역 근처에서 치과를 찾는 분들이라면 참고하기 좋은 곳이라고 느꼈습니다",
    "전체적으로 설명과 응대가 좋아서 다음 진료도 편하게 받을 수 있을 것 같습니다",
    "과하지 않은 안내와 편안한 분위기 덕분에 만족스러운 방문이었습니다",
    "치료 전 걱정이 있었는데 상담과 안내가 꼼꼼해서 좋은 경험으로 남았습니다",
    "마곡 치과를 고민하는 분들에게 자연스럽게 추천하고 싶은 방문이었습니다",
    "설명과 진료 분위기가 안정적이라 앞으로도 편하게 다닐 수 있을 것 같습니다",
    "세심한 상담과 깔끔한 진료 흐름 덕분에 기억에 남는 방문이었습니다",
    "마곡역 주변에서 신뢰감 있는 치과를 찾는 분들에게 도움이 될 것 같습니다",
  ];

  const parts: string[] = [
    pick(openers, seed),
    pick(visitPhrases[visit] || visitPhrases["처음 방문"], seed + 2),
    pick(main.phrases, seed + 5),
  ];

  if (second && style !== "짧게") parts.push(`${second.id} 부분도 함께 상담받을 수 있어 도움이 됐습니다`);

  const brandLimit = style === "짧게" ? 0 : style === "자세하게" ? 2 : 1;
  for (let i = 0; i < brandLimit; i++) {
    parts.push(pick(BRAND_PHRASES, seed + 7 + i));
  }

  const satLimit = style === "짧게" ? 1 : style === "자세하게" ? 3 : 2;
  const convLimit = style === "짧게" ? 1 : style === "자세하게" ? 2 : 1;
  const emoLimit = style === "짧게" ? 1 : style === "자세하게" ? 2 : 1;

  selectedSats.slice(0, satLimit).forEach((item, index) => parts.push(pick(item.phrases, seed + 10 + index)));
  selectedConvs.slice(0, convLimit).forEach((item, index) => parts.push(pick(item.phrases, seed + 20 + index)));
  selectedEmos.slice(0, emoLimit).forEach((item, index) => parts.push(pick(item.phrases, seed + 30 + index)));
  const selectedTone = TONES.find(item => item.id === tone) || TONES[0];
  if (style !== "짧게") parts.push(pick([...closings, ...selectedTone.endings], seed + 40));
  if (style === "짧게" && tone === "친근하게") parts.push("편하게 다녀올 수 있어 좋았습니다");

  return trimByStyle(joinSentences(parts), style);
}


function SectionHeader({ n, label }: { n: number; label: string }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 12, minWidth: 94, flexShrink: 0 }}>
      <span style={{
        width: 26,
        height: 26,
        borderRadius: "50%",
        background: `linear-gradient(135deg, ${BLUE} 0%, #0EA5E9 100%)`,
        color: "white",
        fontSize: 13,
        fontWeight: 900,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        boxShadow: "0 4px 10px rgba(37,99,235,0.24)",
      }}>{n}</span>
      <span style={{ fontSize: 15.5, fontWeight: 900, color: "#0F172A", letterSpacing: -0.5, whiteSpace: "nowrap" }}>{label}</span>
    </div>
  );
}

function Card({ children, mb = 14 }: { children: ReactNode; mb?: number }) {
  return (
    <div style={{
      background: "rgba(255,255,255,0.98)",
      borderRadius: 16,
      padding: "16px 14px",
      marginBottom: mb,
      boxShadow: "0 8px 24px rgba(15,23,42,0.06)",
      border: `1px solid ${BORDER}`,
    }}>
      {children}
    </div>
  );
}

function Toggle2({ options, value, onChange }: { options: { id: string; label: string; sub?: string }[]; value: string; onChange: (v: string) => void }) {
  return (
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, width: "100%" }}>
      {options.map(option => {
        const on = value === option.id;
        return (
          <button key={option.id} onClick={() => onChange(option.id)} style={{
            padding: "13px 10px",
            border: `2px solid ${on ? BLUE : "#BFD3EE"}`,
            borderRadius: 14,
            background: on ? `linear-gradient(135deg, ${BLUE} 0%, #0EA5E9 100%)` : "white",
            color: on ? "white" : "#0F172A",
            cursor: "pointer",
            transition: "all 0.15s",
            width: "100%",
            boxShadow: on ? "0 7px 16px rgba(37,99,235,0.24)" : "none",
            textAlign: "center",
          }}>
            <div style={{ fontSize: 13, fontWeight: 700 }}>{on ? "✓ " : ""}{option.label}</div>
            {option.sub && <div style={{ fontSize: 10.5, opacity: on ? 0.9 : 0.55, marginTop: 3, fontWeight: 650 }}>{option.sub}</div>}
          </button>
        );
      })}
    </div>
  );
}

function OptionGrid({ options, values, onToggle, columns = 2 }: { options: { id: string; icon: string; label: string }[]; values: string[]; onToggle: (id: string) => void; columns?: 2 | 3 }) {
  return (
    <div style={{ display: "grid", gridTemplateColumns: columns === 3 ? "repeat(3, 1fr)" : "1fr 1fr", gap: 10, width: "100%" }}>
      {options.map(option => {
        const on = values.includes(option.id);
        return (
          <button key={option.id} onClick={() => onToggle(option.id)} style={{
            padding: columns === 3 ? "12px 6px 10px" : "12px 10px",
            minHeight: columns === 3 ? 74 : 52,
            border: `2px solid ${on ? BLUE : "#CAD8EA"}`,
            borderRadius: 16,
            background: on ? LBLUE : "white",
            cursor: "pointer",
            display: "flex",
            flexDirection: columns === 3 ? "column" : "row",
            alignItems: "center",
            justifyContent: columns === 3 ? "center" : "flex-start",
            gap: columns === 3 ? 7 : 9,
            transition: "all 0.15s",
            width: "100%",
            minWidth: 0,
            boxShadow: on ? "0 5px 14px rgba(37,99,235,0.12)" : "none",
          }}>
            <span style={{ fontSize: columns === 3 ? 22 : 18, lineHeight: 1, flexShrink: 0 }}>{option.icon}</span>
            <span style={{
              fontSize: columns === 3 ? 11.8 : 13,
              fontWeight: on ? 700 : 500,
              color: on ? BLUE : NAVY,
              whiteSpace: "pre-line",
              lineHeight: 1.25,
              textAlign: columns === 3 ? "center" : "left",
              width: "100%",
              wordBreak: "keep-all",
            }}>{option.label}</span>
          </button>
        );
      })}
    </div>
  );
}

export default function App() {
  const [visit, setVisit] = useState("처음 방문");
  const [tone, setTone] = useState("자세하게");
  const [treats, setTreats] = useState<string[]>([]);
  const [sats, setSats] = useState<string[]>([]);
  const [convs, setConvs] = useState<string[]>([]);
  const [emotions, setEmotions] = useState<string[]>([]);
  const [review, setReview] = useState("");
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);
  const [err, setErr] = useState("");
  const resultRef = useRef<HTMLDivElement | null>(null);

  const toggle = (arr: string[], set: (v: string[]) => void, value: string) =>
    set(arr.includes(value) ? arr.filter(item => item !== value) : [...arr, value]);

  const generate = async () => {
    if (loading) return;
  
    if (treats.length === 0) {
      setErr("치료 항목을 하나 이상 선택해주세요.");
      return;
    }
  
    if (sats.length + convs.length + emotions.length === 0) {
      setErr("좋았던 점, 편의사항, 걱정 포인트 중 하나 이상 선택해주세요.");
      return;
    }
  
    const RATE_KEY = "seouldia_review_generate_log_v1";
    const COOLDOWN_MS = 10 * 1000;
    const DAILY_LIMIT = 3;
  
    const now = Date.now();
    const oneDayAgo = now - 24 * 60 * 60 * 1000;
  
    const getTodayTimestamps = () => {
      try {
        const rawLog = window.localStorage.getItem(RATE_KEY);
        const parsedLog = rawLog ? JSON.parse(rawLog) : [];
  
        return Array.isArray(parsedLog)
          ? parsedLog.filter(
              (time): time is number =>
                typeof time === "number" && time > oneDayAgo
            )
          : [];
      } catch (error) {
        console.warn("Local rate limit read failed:", error);
        return [];
      }
    };
  
    const recordSuccessfulGeneration = () => {
      try {
        const latest = getTodayTimestamps();
        window.localStorage.setItem(RATE_KEY, JSON.stringify([...latest, Date.now()]));
      } catch (error) {
        console.warn("Local rate limit write failed:", error);
      }
    };
  
    const timestamps = getTodayTimestamps();
    const lastGeneratedAt = timestamps[timestamps.length - 1];
  
    if (lastGeneratedAt && now - lastGeneratedAt < COOLDOWN_MS) {
      const waitSeconds = Math.ceil(
        (COOLDOWN_MS - (now - lastGeneratedAt)) / 1000
      );
      setErr(`리뷰 문장은 ${waitSeconds}초 후 다시 만들 수 있습니다.`);
      return;
    }
  
    if (timestamps.length >= DAILY_LIMIT) {
      setErr(
        "오늘 생성 가능한 횟수를 모두 사용했습니다. 작성된 문장을 수정해서 사용해주세요."
      );
      return;
    }
  
    setErr("");
    setLoading(true);
    setCopied(false);
    setReview("");
  
    const fallbackReview = () =>
      createKeywordReview({
        treats,
        sats,
        conveniences: convs,
        emotions,
        visit,
        style: tone,
        tone,
      });
  
    try {
      const response = await fetch("/api/generate-review", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          treatments: treats,
          satisfactions: sats,
          conveniences: convs,
          emotions,
          visit,
          style: tone,
          tone,
        }),
      });
  
      const data: {
        review?: string;
        fallback?: boolean;
        reason?: string;
        error?: string;
        retryAfterSeconds?: number;
        source?: string;
      } = await response.json();
  
      if (response.status === 403) {
        setErr("허용되지 않은 접근입니다. 병원 리뷰 페이지에서 다시 시도해주세요.");
        setReview("");
        return;
      }
  
      if (!response.ok) {
        throw new Error(data.error || "AI 리뷰 생성 요청에 실패했습니다.");
      }
  
      if (data.fallback) {
        setReview(fallbackReview());
        recordSuccessfulGeneration();
        return;
      }
  
      const nextReview =
        typeof data.review === "string" && data.review.trim().length > 0
          ? data.review.trim()
          : fallbackReview();
  
      setReview(nextReview);
      recordSuccessfulGeneration();
    } catch (error) {
      console.error("AI review generation failed:", error);
      setReview(fallbackReview());
      recordSuccessfulGeneration();
    } finally {
      setLoading(false);
  
      window.setTimeout(() => {
        resultRef.current?.scrollIntoView({ behavior: "smooth", block: "start" });
      }, 80);
    }
  };
  
  const copy = async () => {
    if (!review) return;
    await navigator.clipboard.writeText(review);
    setCopied(true);
    setTimeout(() => setCopied(false), 2500);
  };

  return (
    <>
      <GlobalStyle />
      <div style={{
        fontFamily: "'Apple SD Gothic Neo','Noto Sans KR',system-ui,sans-serif",
        background: `linear-gradient(180deg, #EEF5FF 0%, ${BG} 32%, #FFFFFF 100%)`,
        minHeight: "100vh",
        width: "100%",
        maxWidth: 430,
        margin: "0 auto",
        padding: "10px 10px 24px",
      }}>
        <div style={{
          background: "rgba(255,255,255,0.98)",
          borderRadius: 16,
          padding: "22px 16px 18px",
          marginBottom: 14,
          border: `1px solid ${BORDER}`,
          boxShadow: "0 12px 32px rgba(15,23,42,0.08)",
        }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 14, marginBottom: 14 }}>
            <img src={LOGO_SRC} alt="서울디아치과 로고" style={{ width: 92, height: 76, objectFit: "contain", flexShrink: 0 }} />
            <h1 style={{ color: NAVY, fontSize: 26, fontWeight: 700, letterSpacing: -0.8, lineHeight: 1.05 }}>서울디아치과</h1>
          </div>
          <p style={{ color: BLUE, fontSize: 15.5, fontWeight: 900, textAlign: "center", lineHeight: 1.5, letterSpacing: -0.35 }}>
            리뷰 작성을 간편하게 도와드릴게요!
          </p>
          <p style={{ color: "#64748B", fontSize: 13.5, fontWeight: 500, textAlign: "center", lineHeight: 1.55, marginTop: 4 }}>
            진심 담긴 후기는 다른 환자분들에게 도움이 됩니다
          </p>
        </div>

        <div>
          <Card>
            <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
              <SectionHeader n={1} label="방문유형" />
              <Toggle2
                options={[{ id: "처음 방문", label: "처음 방문", sub: "첫 진료·상담" }, { id: "재방문", label: "재방문", sub: "다시 방문" }]}
                value={visit}
                onChange={setVisit}
              />
            </div>
          </Card>

          <Card>
            <div style={{ display: "flex", alignItems: "flex-start", gap: 14 }}>
              <SectionHeader n={2} label="치료선택" />
              <OptionGrid options={TREATMENTS} values={treats} onToggle={id => toggle(treats, setTreats, id)} columns={3} />
            </div>
          </Card>

          <Card>
            <div style={{ display: "flex", alignItems: "flex-start", gap: 14 }}>
              <SectionHeader n={3} label="걱정 포인트" />
              <OptionGrid options={EMOTIONS} values={emotions} onToggle={id => toggle(emotions, setEmotions, id)} columns={2} />
            </div>
          </Card>

          <Card>
            <div style={{ display: "flex", alignItems: "flex-start", gap: 14 }}>
              <SectionHeader n={4} label="좋았던 점" />
              <OptionGrid options={SATISFACTIONS} values={sats} onToggle={id => toggle(sats, setSats, id)} columns={2} />
            </div>
          </Card>

          <Card>
            <div style={{ display: "flex", alignItems: "flex-start", gap: 14 }}>
              <SectionHeader n={5} label="편의·분위기" />
              <OptionGrid options={CONVENIENCES} values={convs} onToggle={id => toggle(convs, setConvs, id)} columns={2} />
            </div>
          </Card>

          <Card>
            <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
              <SectionHeader n={6} label="문체 선택" />
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, width: "100%" }}>
                {TONES.map(item => {
                  const on = tone === item.id;
                  return (
                    <button key={item.id} onClick={() => setTone(item.id)} style={{
                      minHeight: 54,
                      padding: "10px 5px",
                      border: `2px solid ${on ? BLUE : "#BFD3EE"}`,
                      borderRadius: 16,
                      background: on ? `linear-gradient(135deg, ${BLUE} 0%, #0EA5E9 100%)` : "white",
                      color: on ? "white" : NAVY,
                      cursor: "pointer",
                      boxShadow: on ? "0 7px 16px rgba(37,99,235,0.24)" : "none",
                    }}>
                      <div style={{ fontSize: 15, fontWeight: 900 }}>{item.label}</div>
                     
                    </button>
                  );
                })}
              </div>
            </div>
          </Card>

          {err && (
            <div style={{ background: "#FEF2F2", border: "1px solid #FECACA", borderRadius: 16, padding: "13px 16px", color: "#DC2626", fontSize: 15, fontWeight: 700, marginBottom: 14 }}>
              ⚠️ {err}
            </div>
          )}

          <button onClick={generate} disabled={loading} style={{
            width: "100%",
            padding: "16px 0",
            background: loading ? "#93C5FD" : `linear-gradient(135deg,#0EA5E9 0%,${BLUE} 48%,#1D4ED8 100%)`,
            color: "white",
            border: "none",
            borderRadius: 16,
            fontSize: 17,
            fontWeight: 800,
            cursor: loading ? "not-allowed" : "pointer",
            marginBottom: 14,
            letterSpacing: -0.6,
            boxShadow: loading ? "none" : "0 10px 26px rgba(37,99,235,0.28)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            gap: 10,
          }}>
            {loading ? <><Spinner /> 리뷰 만드는 중...</> : "✨ 자연스러운 리뷰 만들기"}
          </button>

          {(review || loading) && (
            <div ref={resultRef} style={{ scrollMarginTop: 16 }}>
              <Card mb={16}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 14 }}>
                  <span style={{ fontSize: 16 }}>✨</span>
                  <span style={{ fontSize: 16, fontWeight: 700, color: NAVY }}>생성된 리뷰</span>
                </div>

                {loading ? (
                  <div style={{
                    minHeight: 150,
                    border: "1.5px solid #BFD3EE",
                    background: "#F8FBFF",
                    borderRadius: 16,
                    padding: 18,
                    display: "flex",
                    alignItems: "center",
                    gap: 10,
                    color: "#64748B",
                    fontSize: 13.5,
                    fontWeight: 700,
                  }}>
                    <Spinner color={BLUE} /> 리뷰 문장을 자연스럽게 만들고 있어요...
                  </div>
                ) : (
                  <>
                    <div style={{
                      border: "1.8px solid #AFC9F3",
                      background: "linear-gradient(180deg, #FFFFFF 0%, #F8FBFF 100%)",
                      borderRadius: 16,
                      padding: "15px 14px",
                      color: "#0F172A",
                      fontSize: 13.5,
                      lineHeight: 1.85,
                      fontWeight: 650,
                      wordBreak: "keep-all",
                      whiteSpace: "pre-wrap",
                    }}>
                      {review}
                    </div>

                    <button onClick={copy} style={{
                      width: "100%",
                      marginTop: 12,
                      padding: "13px 0",
                      border: "1.6px solid #BFD3EE",
                      background: copied ? "#ECFDF5" : "white",
                      color: copied ? "#16A34A" : BLUE,
                      borderRadius: 14,
                      fontSize: 13,
                      fontWeight: 900,
                      cursor: "pointer",
                    }}>
                      {copied ? "✓ 복사되었습니다! 사진도 함께 올려볼까요??📸" : "📋 문구 복사하기"}
                    </button>
                  </>
                )}
              </Card>
            </div>
          )}

          <p style={{ fontSize: 10.5, color: "#94A3B8", textAlign: "center", lineHeight: 1.6, padding: "0 0 12px" }}>
            ※ 생성된 문장은 참고용 예시입니다. 실제 경험에 맞게 수정 후 사용해주세요.
          </p>

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, paddingBottom: "calc(8px + env(safe-area-inset-bottom, 0px))" }}>
            {NAV_BTNS.map(button => (
              <a key={button.label} href={button.url} target="_blank" rel="noopener noreferrer" style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: 10,
                minHeight: 54,
                background: "white",
                border: `2px solid ${button.label.includes("네이버") ? "#22C55E" : BORDER}`,
                borderRadius: 18,
                color: button.label.includes("네이버") ? "#16A34A" : NAVY,
                textDecoration: "none",
                fontSize: 15,
                fontWeight: 700,
                boxShadow: "0 7px 18px rgba(15,23,42,0.05)",
              }}>
                <span style={{
                  width: 28,
                  height: 28,
                  borderRadius: 9,
                  background: button.bg,
                  color: "white",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 15,
                  fontWeight: 700,
                }}>{button.icon}</span>
                {button.label} <span style={{ opacity: 0.65 }}>›</span>
              </a>
            ))}
          </div>
        </div>      </div>
    </>
  );
}

function GlobalStyle() {
  return <style>{`
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    html, body, #root { width: 100%; max-width: 100vw; overflow-x: hidden; background: #F4F7FB; -webkit-text-size-adjust: 100%; }
    button, a { font-family: inherit; -webkit-tap-highlight-color: transparent; }
    @keyframes _spin { to { transform: rotate(360deg); } }
  `}</style>;
}


function Spinner({ color = "white" }: { color?: string }) {
  return (
    <span style={{
      width: 18,
      height: 18,
      borderRadius: "50%",
      border: `3px solid ${color === "white" ? "rgba(255,255,255,0.35)" : "#DCEBFF"}`,
      borderTopColor: color,
      animation: "_spin 0.7s linear infinite",
      display: "inline-block",
      flexShrink: 0,
    }} />
  );
}
